CREATE OR REPLACE FUNCTION public.protect_building_id()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF pg_trigger_depth() > 1 THEN
    RETURN NEW;
  END IF;
  IF OLD.building_id IS NOT NULL AND NEW.building_id IS NULL THEN
    NEW.building_id = OLD.building_id;
  END IF;
  RETURN NEW;
END;
$function$
